1	/* parser.h -- PL/SW declaration parser */
2	/* Parses DCL statements into AST nodes */
3	
4	#ifndef PARSER_H
5	#define PARSER_H
6	
7	#include "lexer.h"
8	#include "ast.h"
9	
10	/* Parser error state */
11	int parse_err;          /* 0 = ok, 1 = error */
12	char parse_errmsg[64];  /* error description */
13	
14	void parse_init(char *src) {
15	    parse_err = 0;
16	    parse_errmsg[0] = 0;
17	    lex_init(src, str_len(src));
18	    lex_scan();  /* prime the first token */
19	}
20	
21	/* Report a parse error */
22	void parse_error(char *msg) {
23	    parse_err = 1;
24	    str_copy(parse_errmsg, msg);
25	    uart_putstr("ERROR: ");
26	    uart_puts(msg);
27	}
28	
29	/* Check if current token matches type */
30	int parse_check(int type) {
31	    return cur_type == type;
32	}
33	
34	/* Consume current token and advance */
35	void parse_advance(void) {
36	    lex_scan();
37	}
38	
39	/* Expect a specific token; consume and advance. Error if wrong. */
40	int parse_expect(int type) {
41	    if (cur_type != type) {
42	        uart_putstr("expected ");
43	        uart_putstr(tok_name(type));
44	        uart_putstr(" got ");
45	        uart_putstr(tok_name(cur_type));
46	        uart_putchar(10);
47	        parse_error("unexpected token");
48	        return 0;
49	    }
50	    parse_advance();
51	    return 1;
52	}
53	
54	/* Try to match a token; consume if matched, return 1. Else return 0. */
55	int parse_match(int type) {
56	    if (cur_type == type) {
57	        parse_advance();
58	        return 1;
59	    }
60	    return 0;
61	}
62	
63	/* --- Type parsing --- */
64	
65	/* Parse a type keyword and return the TYPE_ constant.
66	   Handles INT(n) where n determines INT8/INT16/INT24.
67	   Returns TYPE_NONE if no type keyword found. */
68	int parse_type(void) {
69	    if (cur_type == TOK_INT) {
70	        parse_advance();
71	        /* optional width: INT(8), INT(16), INT(24) */
72	        if (parse_check(TOK_LPAREN)) {
73	            parse_advance();
74	            int width = cur_ival;
75	            parse_expect(TOK_NUM);
76	            parse_expect(TOK_RPAREN);
77	            if (width <= 8) return TYPE_INT8;
78	            if (width <= 16) return TYPE_INT16;
79	            return TYPE_INT24;
80	        }
81	        return TYPE_INT24;  /* default INT = INT(24) */
82	    }
83	    if (cur_type == TOK_BYTE) { parse_advance(); return TYPE_BYTE; }
84	    if (cur_type == TOK_CHAR) { parse_advance(); return TYPE_CHAR; }
85	    if (cur_type == TOK_PTR)  { parse_advance(); return TYPE_PTR; }
86	    if (cur_type == TOK_WORD) { parse_advance(); return TYPE_WORD; }
87	    if (cur_type == TOK_BIT)  { parse_advance(); return TYPE_BIT; }
88	    return TYPE_NONE;
89	}
90	
91	/* --- Storage class parsing --- */
92	
93	/* Parse optional storage class. Returns STOR_ constant. */
94	int parse_storage(void) {
95	    if (cur_type == TOK_STATIC)   { parse_advance(); return STOR_STATIC; }
96	    if (cur_type == TOK_AUTO)     { parse_advance(); return STOR_AUTO; }
97	    if (cur_type == TOK_EXTERNAL) { parse_advance(); return STOR_EXTERNAL; }
98	    if (cur_type == TOK_BASED)    { parse_advance(); return STOR_BASED; }
99	    return STOR_AUTO;
100	}
101	
102	/* --- INIT parsing --- */
103	
104	/* Parse INIT(value) -- returns node index or NODE_NULL */
105	int parse_init_attr(void) {
106	    if (cur_type != TOK_INIT) return NODE_NULL;
107	    parse_advance();  /* consume INIT */
108	    parse_expect(TOK_LPAREN);
109	    int init_node = NODE_NULL;
110	    if (cur_type == TOK_NUM) {
111	        init_node = nd_literal(cur_ival);
112	        parse_advance();
113	    } else if (cur_type == TOK_STRING) {
114	        init_node = nd_alloc(NODE_LITERAL);
115	        if (init_node != NODE_NULL) {
116	            nd_set_name(init_node, cur_text);
117	            nd_type[init_node] = TYPE_CHAR;
118	        }
119	        parse_advance();
120	    } else {
121	        parse_error("expected literal in INIT");
122	        return NODE_NULL;
123	    }
124	    parse_expect(TOK_RPAREN);
125	    return init_node;
126	}
127	
128	/* --- DCL parsing --- */
129	
130	/* Parse a single scalar/array declaration field.
131	   Used for both top-level DCL and level-based fields.
132	   Returns the DCL node index. */
133	int parse_dcl_field(int level) {
134	    if (cur_type != TOK_IDENT) {
135	        parse_error("expected identifier in DCL");
136	        return NODE_NULL;
137	    }
138	
139	    /* Save name in arena (avoids large stack local) */
140	    int nlen = str_len(cur_text);
141	    char *name = arena_alloc(nlen + 1);
142	    if (!name) {
143	        parse_error("arena full");
144	        return NODE_NULL;
145	    }
146	    str_copy(name, cur_text);
147	    parse_advance();
148	
149	    /* Check for array dimension: NAME(dim) */
150	    int dim = 0;
151	    if (parse_check(TOK_LPAREN)) {
152	        parse_advance();
153	        if (cur_type == TOK_NUM) {
154	            dim = cur_ival;
155	            parse_advance();
156	        } else {
157	            parse_error("expected number for array dimension");
158	            return NODE_NULL;
159	        }
160	        parse_expect(TOK_RPAREN);
161	    }
162	
163	    /* Parse type */
164	    int type = parse_type();
165	
166	    /* Parse storage class */
167	    int stor = parse_storage();
168	
169	    /* Parse optional INIT */
170	    int init = parse_init_attr();
171	
172	    /* Build the DCL node */
173	    int n = nd_alloc(NODE_DCL);
174	    if (n == NODE_NULL) {
175	        parse_error("node pool full");
176	        return NODE_NULL;
177	    }
178	    /* name is already in arena, just assign directly */
179	    nd_name[n] = name;
180	    nd_type[n] = type;
181	    nd_stor[n] = stor;
182	    nd_level[n] = level;
183	    nd_ival[n] = dim;
184	    nd_right[n] = init;  /* init expression, or NODE_NULL */
185	
186	    return n;
187	}
188	
189	/* Parse a level-based record declaration.
190	   Called after DCL and the first level number have been consumed.
191	   Syntax: DCL 1 NAME, 3 FIELD TYPE, 3 FIELD TYPE, ...;
192	
193	   Level 1 = record container, 3+ = fields.
194	   Lower level numbers start new groups. */
195	int parse_dcl_record(int first_level) {
196	    /* Parse the record name */
197	    if (cur_type != TOK_IDENT) {
198	        parse_error("expected record name");
199	        return NODE_NULL;
200	    }
201	
202	    /* Create record container node */
203	    int rec = nd_alloc(NODE_DCL);
204	    if (rec == NODE_NULL) {
205	        parse_error("node pool full");
206	        return NODE_NULL;
207	    }
208	    nd_set_name(rec, cur_text);
209	    nd_type[rec] = TYPE_RECORD;
210	    nd_level[rec] = first_level;
211	    parse_advance();
212	
213	    /* Parse optional storage class on record itself */
214	    nd_stor[rec] = parse_storage();
215	
216	    /* Expect comma or semicolon after record name */
217	    if (!parse_match(TOK_COMMA)) {
218	        /* Record with no fields -- just a named type */
219	        parse_expect(TOK_SEMI);
220	        return rec;
221	    }
222	
223	    /* Parse fields: level NAME type, ... ; */
224	    while (!parse_err) {
225	        /* Expect a level number */
226	        if (cur_type != TOK_NUM) {
227	            parse_error("expected level number");
228	            return rec;
229	        }
230	        int field_level = cur_ival;
231	        parse_advance();
232	
233	        /* Parse the field */
234	        int field = parse_dcl_field(field_level);
235	        if (field == NODE_NULL) return rec;
236	
237	        /* Append field as child of record */
238	        nd_append(rec, field);
239	
240	        /* Comma means more fields, semicolon ends */
241	        if (parse_check(TOK_SEMI)) {
242	            parse_advance();
243	            break;
244	        }
245	        if (!parse_match(TOK_COMMA)) {
246	            parse_error("expected , or ; in record DCL");
247	            return rec;
248	        }
249	    }
250	
251	    return rec;
252	}
253	
254	/* Parse a DCL statement. Handles:
255	   - DCL NAME TYPE;
256	   - DCL NAME(dim) TYPE;
257	   - DCL NAME TYPE STATIC;
258	   - DCL NAME TYPE INIT(val);
259	   - DCL 1 NAME, 3 FIELD TYPE, ...;
260	   Returns the root DCL node index. */
261	int parse_dcl(void) {
262	    /* Consume DCL or DECLARE */
263	    if (cur_type != TOK_DCL && cur_type != TOK_DECLARE) {
264	        parse_error("expected DCL");
265	        return NODE_NULL;
266	    }
267	    parse_advance();
268	
269	    /* Check if level-based record: DCL <number> ... */
270	    if (cur_type == TOK_NUM) {
271	        int level = cur_ival;
272	        parse_advance();
273	        return parse_dcl_record(level);
274	    }
275	
276	    /* Simple scalar or array declaration */
277	    int n = parse_dcl_field(0);
278	    if (n == NODE_NULL) return NODE_NULL;
279	
280	    /* Expect semicolon */
281	    parse_expect(TOK_SEMI);
282	
283	    return n;
284	}
285	
286	#endif
