1	/* ast.h -- AST node types and pool for PL/SW compiler */
2	/* Uses parallel arrays instead of structs (tc24r workaround) */
3	
4	#ifndef AST_H
5	#define AST_H
6	
7	#include "arena.h"
8	
9	/* Node kind constants */
10	#define NODE_NONE          0
11	#define NODE_PROGRAM       1
12	#define NODE_DCL           2
13	#define NODE_PROC          3
14	#define NODE_IF            4
15	#define NODE_DO_WHILE      5
16	#define NODE_DO_COUNT      6
17	#define NODE_ASSIGN        7
18	#define NODE_BINOP         8
19	#define NODE_UNOP          9
20	#define NODE_CALL         10
21	#define NODE_RETURN       11
22	#define NODE_LITERAL      12
23	#define NODE_IDENT        13
24	#define NODE_ASM_BLOCK    14
25	#define NODE_FIELD_ACCESS 15
26	#define NODE_ARRAY_ACCESS 16
27	#define NODE_ADDR         17
28	#define NODE_DEREF        18
29	#define NODE_BLOCK        19
30	
31	/* Type info constants */
32	#define TYPE_NONE    0
33	#define TYPE_INT8    1
34	#define TYPE_INT16   2
35	#define TYPE_INT24   3
36	#define TYPE_BYTE    4
37	#define TYPE_CHAR    5
38	#define TYPE_BIT     6
39	#define TYPE_WORD    7
40	#define TYPE_PTR     8
41	#define TYPE_ARRAY   9
42	#define TYPE_RECORD  10
43	
44	/* Storage class constants */
45	#define STOR_AUTO     0
46	#define STOR_STATIC   1
47	#define STOR_EXTERNAL 2
48	#define STOR_BASED    3
49	
50	/* Null node index sentinel */
51	#define NODE_NULL (-1)
52	
53	/* Node pool -- parallel arrays, 256 nodes max */
54	#define NODE_POOL_MAX 256
55	
56	int nd_kind[NODE_POOL_MAX];       /* node kind */
57	int nd_type[NODE_POOL_MAX];       /* type info */
58	int nd_stor[NODE_POOL_MAX];       /* storage class */
59	int nd_level[NODE_POOL_MAX];      /* DCL level (1,3,5,...) */
60	int nd_left[NODE_POOL_MAX];       /* left child index */
61	int nd_right[NODE_POOL_MAX];      /* right child index */
62	int nd_next[NODE_POOL_MAX];       /* sibling/next index */
63	int nd_ival[NODE_POOL_MAX];       /* integer value or operator */
64	char *nd_name[NODE_POOL_MAX];     /* name (arena-allocated) */
65	
66	int nd_count;                     /* number of allocated nodes */
67	
68	void ast_init(void) {
69	    nd_count = 0;
70	}
71	
72	/* Allocate a new node. Returns node index or NODE_NULL on OOM. */
73	int nd_alloc(int kind) {
74	    if (nd_count >= NODE_POOL_MAX) {
75	        return NODE_NULL;
76	    }
77	    int i = nd_count;
78	    nd_count = nd_count + 1;
79	    nd_kind[i]  = kind;
80	    nd_type[i]  = TYPE_NONE;
81	    nd_stor[i]  = STOR_AUTO;
82	    nd_level[i] = 0;
83	    nd_left[i]  = NODE_NULL;
84	    nd_right[i] = NODE_NULL;
85	    nd_next[i]  = NODE_NULL;
86	    nd_ival[i]  = 0;
87	    nd_name[i]  = 0;
88	    return i;
89	}
90	
91	/* Set the name on a node (copies string into arena) */
92	void nd_set_name(int n, char *name) {
93	    if (n < 0 || n >= nd_count) return;
94	    int len = str_len(name);
95	    char *s = arena_alloc(len + 1);
96	    if (s) {
97	        str_copy(s, name);
98	        nd_name[n] = s;
99	    }
100	}
101	
102	/* Append child to end of a node's sibling chain via nd_next */
103	void nd_append(int parent, int child) {
104	    if (parent < 0 || child < 0) return;
105	    /* Find the appropriate child slot */
106	    if (nd_left[parent] == NODE_NULL) {
107	        nd_left[parent] = child;
108	        return;
109	    }
110	    /* Walk the sibling chain from left child */
111	    int cur = nd_left[parent];
112	    while (nd_next[cur] != NODE_NULL) {
113	        cur = nd_next[cur];
114	    }
115	    nd_next[cur] = child;
116	}
117	
118	/* Create a literal node */
119	int nd_literal(int value) {
120	    int n = nd_alloc(NODE_LITERAL);
121	    if (n != NODE_NULL) {
122	        nd_ival[n] = value;
123	        nd_type[n] = TYPE_INT24;
124	    }
125	    return n;
126	}
127	
128	/* Create an identifier node */
129	int nd_ident(char *name) {
130	    int n = nd_alloc(NODE_IDENT);
131	    if (n != NODE_NULL) {
132	        nd_set_name(n, name);
133	    }
134	    return n;
135	}
136	
137	/* Create a binary operator node */
138	int nd_binop(int op, int left, int right) {
139	    int n = nd_alloc(NODE_BINOP);
140	    if (n != NODE_NULL) {
141	        nd_ival[n] = op;
142	        nd_left[n] = left;
143	        nd_right[n] = right;
144	    }
145	    return n;
146	}
147	
148	/* Create a unary operator node */
149	int nd_unop(int op, int operand) {
150	    int n = nd_alloc(NODE_UNOP);
