1	/* lexer.h -- PL/SW lexer for COR24 compiler */
2	/* Scans input buffer producing tokens */
3	
4	#ifndef LEXER_H
5	#define LEXER_H
6	
7	#include "token.h"
8	
9	/* Lexer state */
10	char *lex_src;    /* source buffer pointer */
11	int   lex_pos;    /* current position in source */
12	int   lex_len;    /* length of source */
13	
14	/* Current token (globals -- no struct on stack) */
15	int  cur_type;
16	int  cur_ival;
17	char cur_text[TOK_TEXT_MAX];
18	
19	/* Initialize lexer with a source buffer */
20	void lex_init(char *src, int len) {
21	    lex_src = src;
22	    lex_pos = 0;
23	    lex_len = len;
24	    kw_init();
25	}
26	
27	/* Peek at current character without advancing */
28	int lex_peek(void) {
29	    if (lex_pos >= lex_len) return 0;
30	    return lex_src[lex_pos];
31	}
32	
33	/* Advance and return current character */
34	int lex_advance(void) {
35	    if (lex_pos >= lex_len) return 0;
36	    int c = lex_src[lex_pos];
37	    lex_pos = lex_pos + 1;
38	    return c;
39	}
40	
41	/* Peek at next character (one ahead) */
42	int lex_peek2(void) {
43	    if (lex_pos + 1 >= lex_len) return 0;
44	    return lex_src[lex_pos + 1];
45	}
46	
47	/* Character classification */
48	int is_alpha(int c) {
49	    return (c >= 65 && c <= 90) || (c >= 97 && c <= 122) || c == 95;
50	}
51	
52	int is_digit(int c) {
53	    return c >= 48 && c <= 57;
54	}
55	
56	int is_alnum(int c) {
57	    return is_alpha(c) || is_digit(c);
58	}
59	
60	int is_space(int c) {
61	    return c == 32 || c == 9 || c == 10 || c == 13;
62	}
63	
64	/* Skip whitespace and comments */
65	void lex_skip(void) {
66	    while (lex_pos < lex_len) {
67	        int c = lex_peek();
68	
69	        if (is_space(c)) {
70	            lex_advance();
71	            continue;
72	        }
73	
74	        /* block comment: / * ... * / */
75	        if (c == 47 && lex_peek2() == 42) {
76	            lex_advance();
77	            lex_advance();
78	            while (lex_pos < lex_len) {
79	                if (lex_peek() == 42 && lex_peek2() == 47) {
80	                    lex_advance();
81	                    lex_advance();
82	                    break;
83	                }
84	                lex_advance();
85	            }
86	            continue;
87	        }
88	
89	        break;
90	    }
91	}
92	
93	/* Set current token to a simple operator */
94	void lex_set(int type, char *txt) {
95	    cur_type = type;
96	    cur_ival = 0;
97	    str_copy(cur_text, txt);
98	}
99	
100	/* Scan the next token. Result stored in cur_type/cur_ival/cur_text. */
101	int lex_scan(void) {
102	    lex_skip();
103	
104	    cur_ival = 0;
105	    cur_text[0] = 0;
106	
107	    if (lex_pos >= lex_len) {
108	        cur_type = TOK_EOF;
109	        str_copy(cur_text, "EOF");
110	        return TOK_EOF;
111	    }
112	
113	    int c = lex_peek();
114	
115	    /* Identifier or keyword */
116	    if (is_alpha(c)) {
117	        int i = 0;
118	        while (lex_pos < lex_len && is_alnum(lex_peek()) && i < TOK_TEXT_MAX - 1) {
119	            cur_text[i] = lex_advance();
120	            i = i + 1;
121	        }
122	        cur_text[i] = 0;
123	        cur_type = kw_lookup(cur_text);
124	        return cur_type;
125	    }
126	
127	    /* Number */
128	    if (is_digit(c)) {
129	        int i = 0;
130	        int val = 0;
131	        while (lex_pos < lex_len && is_digit(lex_peek()) && i < TOK_TEXT_MAX - 1) {
132	            int d = lex_advance();
133	            cur_text[i] = d;
134	            val = val * 10 + (d - 48);
135	            i = i + 1;
136	        }
137	        cur_text[i] = 0;
138	        cur_type = TOK_NUM;
139	        cur_ival = val;
140	        return TOK_NUM;
141	    }
142	
143	    /* String literal (single-quoted) */
144	    if (c == 39) {
145	        lex_advance(); /* skip opening quote */
146	        int i = 0;
147	        while (lex_pos < lex_len && lex_peek() != 39 && i < TOK_TEXT_MAX - 1) {
148	            cur_text[i] = lex_advance();
149	            i = i + 1;
150	        }
151	        cur_text[i] = 0;
152	        if (lex_pos < lex_len && lex_peek() == 39) {
153	            lex_advance(); /* skip closing quote */
154	        }
155	        cur_type = TOK_STRING;
156	        return TOK_STRING;
157	    }
158	
159	    /* Operators and punctuation */
160	    lex_advance(); /* consume the character */
161	
162	    if (c == 43) { lex_set(TOK_PLUS, "+"); return TOK_PLUS; }
163	    if (c == 42) { lex_set(TOK_STAR, "*"); return TOK_STAR; }
164	    if (c == 47) { lex_set(TOK_SLASH, "/"); return TOK_SLASH; }
165	    if (c == 38) { lex_set(TOK_AMP, "&"); return TOK_AMP; }
166	    if (c == 124) { lex_set(TOK_PIPE, "|"); return TOK_PIPE; }
167	    if (c == 94) { lex_set(TOK_CARET, "^"); return TOK_CARET; }
168	    if (c == 126) { lex_set(TOK_TILDE, "~"); return TOK_TILDE; }
169	    if (c == 61) { lex_set(TOK_EQ, "="); return TOK_EQ; }
170	    if (c == 40) { lex_set(TOK_LPAREN, "("); return TOK_LPAREN; }
171	    if (c == 41) { lex_set(TOK_RPAREN, ")"); return TOK_RPAREN; }
172	    if (c == 44) { lex_set(TOK_COMMA, ","); return TOK_COMMA; }
173	    if (c == 59) { lex_set(TOK_SEMI, ";"); return TOK_SEMI; }
174	    if (c == 46) { lex_set(TOK_DOT, "."); return TOK_DOT; }
175	    if (c == 63) { lex_set(TOK_QUESTION, "?"); return TOK_QUESTION; }
176	    if (c == 37) { lex_set(TOK_PERCENT, "%"); return TOK_PERCENT; }
177	    if (c == 58) { lex_set(TOK_COLON, ":"); return TOK_COLON; }
178	
179	    if (c == 45) { /* - */
180	        if (lex_peek() == 62) {
181	            lex_advance();
182	            lex_set(TOK_ARROW, "->");
183	            return TOK_ARROW;
184	        }
185	        lex_set(TOK_MINUS, "-");
186	        return TOK_MINUS;
187	    }
188	    if (c == 33) { /* ! */
189	        if (lex_peek() == 61) {
190	            lex_advance();
191	            lex_set(TOK_NE, "!=");
192	            return TOK_NE;
193	        }
194	        lex_set(TOK_TILDE, "!");
195	        return TOK_TILDE;
196	    }
197	    if (c == 60) { /* < */
198	        if (lex_peek() == 61) {
199	            lex_advance();
200	            lex_set(TOK_LE, "<=");
201	            return TOK_LE;
202	        }
203	        if (lex_peek() == 60) {
204	            lex_advance();
205	            lex_set(TOK_SHL, "<<");
206	            return TOK_SHL;
207	        }
208	        lex_set(TOK_LT, "<");
209	        return TOK_LT;
210	    }
211	    if (c == 62) { /* > */
212	        if (lex_peek() == 61) {
213	            lex_advance();
214	            lex_set(TOK_GE, ">=");
215	            return TOK_GE;
216	        }
217	        if (lex_peek() == 62) {
218	            lex_advance();
219	            lex_set(TOK_SHR, ">>");
220	            return TOK_SHR;
221	        }
222	        lex_set(TOK_GT, ">");
223	        return TOK_GT;
224	    }
225	
226	    /* Unknown character */
227	    cur_text[0] = c;
228	    cur_text[1] = 0;
229	    cur_type = TOK_EOF;
230	    return TOK_EOF;
231	}
232	
233	/* Print the current token for debugging */
234	void tok_print(void) {
235	    uart_putstr("  ");
236	    uart_putstr(tok_name(cur_type));
237	    if (cur_type == TOK_IDENT || cur_type == TOK_STRING) {
238	        uart_putstr("(");
239	        uart_putstr(cur_text);
240	        uart_putstr(")");
241	    } else if (cur_type == TOK_NUM) {
242	        uart_putstr("(");
243	        print_int(cur_ival);
244	        uart_putstr(")");
245	    }
246	    uart_putchar(10);
247	}
248	
249	/* Tokenize a source string and print all tokens */
250	void lex_dump(char *label, char *src) {
251	    uart_putstr("--- ");
252	    uart_putstr(label);
253	    uart_puts(" ---");
254	
255	    lex_init(src, str_len(src));
256	    while (1) {
